/* ============================================
   CINEMATIC BEAR SPRAY ANIMATION
   ============================================ */
var sprayAnimState = {
  playing: false,
  phase: 0,
  elapsed: 0,
  lastTime: 0,
  rafId: null,
  started: false
};

var SPRAY_PHASES = [
  { name: 'SPOT THE BEAR',       start: 0,  end: 2,  label: 'Spot' },
  { name: 'DRAW YOUR SPRAY',     start: 2,  end: 4,  label: 'Draw' },
  { name: 'AIM SLIGHTLY DOWN',   start: 4,  end: 6,  label: 'Aim' },
  { name: 'SPRAY IN BURSTS',     start: 6,  end: 9,  label: 'Spray' },
  { name: 'BEAR RETREATS',       start: 9,  end: 11, label: 'Retreat' },
  { name: 'BACK AWAY SLOWLY',    start: 11, end: 13, label: 'Back Away' }
];

var TOTAL_DURATION = 13;

function initSprayAnimation() {
  var container = document.getElementById('spray-demo-container');
  if (!container) return;

  var observer = new IntersectionObserver(function(entries) {
    entries.forEach(function(entry) {
      if (entry.isIntersecting && !sprayAnimState.started) {
        startSprayAnim();
        sprayAnimState.started = true;
      }
    });
  }, { threshold: 0.3 });

  observer.observe(container);
}

function startSprayAnim() {
  sprayAnimState.playing = true;
  sprayAnimState.elapsed = 0;
  sprayAnimState.phase = 0;
  sprayAnimState.lastTime = performance.now();
  resetAnimElements();
  animLoop(sprayAnimState.lastTime);
}

function toggleSprayAnim() {
  if (sprayAnimState.playing) {
    sprayAnimState.playing = false;
    if (sprayAnimState.rafId) cancelAnimationFrame(sprayAnimState.rafId);
    document.getElementById('anim-pause-icon').style.display = 'none';
    document.getElementById('anim-play-icon').style.display = 'block';
  } else {
    sprayAnimState.playing = true;
    sprayAnimState.lastTime = performance.now();
    document.getElementById('anim-pause-icon').style.display = 'block';
    document.getElementById('anim-play-icon').style.display = 'none';
    animLoop(sprayAnimState.lastTime);
  }
}

function animLoop(now) {
  if (!sprayAnimState.playing) return;

  var dt = (now - sprayAnimState.lastTime) / 1000;
  sprayAnimState.lastTime = now;
  sprayAnimState.elapsed += dt;

  if (sprayAnimState.elapsed >= TOTAL_DURATION) {
    sprayAnimState.elapsed = 0;
    sprayAnimState.phase = 0;
    resetAnimElements();
  }

  var t = sprayAnimState.elapsed;

  // Determine current phase
  var currentPhase = 0;
  for (var i = 0; i < SPRAY_PHASES.length; i++) {
    if (t >= SPRAY_PHASES[i].start && t < SPRAY_PHASES[i].end) {
      currentPhase = i;
      break;
    }
    if (i === SPRAY_PHASES.length - 1) currentPhase = i;
  }

  // Update phase label
  if (currentPhase !== sprayAnimState.phase) {
    sprayAnimState.phase = currentPhase;
  }

  var phaseLabel = document.getElementById('anim-phase-label');
  if (phaseLabel) phaseLabel.textContent = SPRAY_PHASES[currentPhase].name;

  // Update progress bar
  var progressFill = document.getElementById('anim-progress-fill');
  if (progressFill) {
    var pct = (t / TOTAL_DURATION) * 100;
    progressFill.style.width = pct + '%';
  }

  // Update phase dots
  var dots = document.querySelectorAll('.anim-phase-dot');
  dots.forEach(function(dot, idx) {
    dot.classList.remove('active', 'completed');
    if (idx === currentPhase) {
      dot.classList.add('active');
    } else if (idx < currentPhase) {
      dot.classList.add('completed');
    }
  });

  // Get elements
  var hiker = document.getElementById('anim-hiker');
  var bear = document.getElementById('anim-bear');
  var sprayCloud = document.getElementById('anim-spray-cloud');
  var hikerAlert = document.getElementById('hiker-alert');
  var sprayCan = document.getElementById('hiker-spray-can');
  var armL = document.getElementById('hiker-arm-l');
  var armR = document.getElementById('hiker-arm-r');
  var callout1 = document.getElementById('callout-1');
  var callout2 = document.getElementById('callout-2');
  var callout3 = document.getElementById('callout-3');

  // Phase 0: SPOT (0-2s) - Bear approaches, hiker notices
  if (t < 2) {
    var p = t / 2;
    // Bear walks left toward hiker
    var bearX = 750 - (p * 250);
    bear.setAttribute('transform', 'translate(' + bearX + ',170)');
    // Hiker stays put, alert appears at t > 0.5
    if (t > 0.5) {
      var alertOpacity = Math.min(1, (t - 0.5) / 0.5);
      hikerAlert.setAttribute('opacity', alertOpacity);
      hikerAlert.classList.add('show');
    }
    hiker.setAttribute('transform', 'translate(140,155)');
  }
  // Phase 1: DRAW (2-4s) - Hiker draws spray can
  else if (t < 4) {
    var p = (t - 2) / 2;
    // Bear continues approaching slowly
    var bearX = 500 - (p * 80);
    bear.setAttribute('transform', 'translate(' + bearX + ',170)');
    // Alert fades out
    hikerAlert.setAttribute('opacity', Math.max(0, 1 - p * 2));
    if (p > 0.5) hikerAlert.classList.remove('show');
    // Spray can appears
    sprayCan.setAttribute('opacity', Math.min(1, p * 3));
    // Arms move to ready position
    armR.setAttribute('x2', 30 - (p * 8));
    armR.setAttribute('y2', 55 - (p * 15));
  }
  // Phase 2: AIM (4-6s) - Hiker aims, callout 1 appears
  else if (t < 6) {
    var p = (t - 4) / 2;
    // Bear still approaching
    var bearX = 420 - (p * 60);
    bear.setAttribute('transform', 'translate(' + bearX + ',170)');
    // Arms in aim position
    sprayCan.setAttribute('opacity', 1);
    armR.setAttribute('x2', 22 + (p * 10));
    armR.setAttribute('y2', 40 - (p * 8));
    armL.setAttribute('x2', -6 + (p * 14));
    armL.setAttribute('y2', 55 - (p * 18));
    // Callout 1 appears
    callout1.setAttribute('opacity', Math.min(1, p * 2));
  }
  // Phase 3: SPRAY (6-9s) - Spray cloud, callouts 2 & 3
  else if (t < 9) {
    var p = (t - 6) / 3;
    var bearX = 360 + (p * 100);
    bear.setAttribute('transform', 'translate(' + bearX + ',170) scale(-1,1)');
    // Spray cloud visible and pulsing
    var cloudOpacity = Math.min(1, p * 3);
    sprayCloud.setAttribute('opacity', cloudOpacity);
    sprayCloud.classList.add('spraying');
    sprayCloud.setAttribute('transform', 'scale(' + (0.8 + p * 0.4) + ')');
    // Keep hiker aiming
    sprayCan.setAttribute('opacity', 1);
    armR.setAttribute('x2', '32');
    armR.setAttribute('y2', '32');
    armL.setAttribute('x2', '8');
    armL.setAttribute('y2', '37');
    // Callout 1 fades, 2 and 3 appear
    callout1.setAttribute('opacity', Math.max(0, 1 - p * 3));
    if (p > 0.2) callout2.setAttribute('opacity', Math.min(1, (p - 0.2) * 3));
    if (p > 0.5) callout3.setAttribute('opacity', Math.min(1, (p - 0.5) * 3));
  }
  // Phase 4: RETREAT (9-11s) - Bear runs away
  else if (t < 11) {
    var p = (t - 9) / 2;
    // Bear retreats quickly
    var bearX = 460 + (p * 350);
    bear.setAttribute('transform', 'translate(' + bearX + ',170) scale(-1,1)');
    // Spray cloud fades
    sprayCloud.setAttribute('opacity', Math.max(0, 1 - p * 2));
    if (p > 0.5) sprayCloud.classList.remove('spraying');
    sprayCloud.setAttribute('transform', 'scale(' + (1.2 - p * 0.4) + ')');
    // Callouts fade
    callout2.setAttribute('opacity', Math.max(0, 1 - p * 2));
    callout3.setAttribute('opacity', Math.max(0, 1 - p * 2));
    // Hiker lowers arms
    sprayCan.setAttribute('opacity', Math.max(0, 1 - p));
    armR.setAttribute('x2', 32 - (p * 2));
    armR.setAttribute('y2', 32 + (p * 23));
    armL.setAttribute('x2', 8 - (p * 14));
    armL.setAttribute('y2', 37 + (p * 18));
  }
  // Phase 5: BACK AWAY (11-13s) - Hiker backs away
  else if (t < 13) {
    var p = (t - 11) / 2;
    // Bear is gone
    bear.setAttribute('transform', 'translate(810,170) scale(-1,1)');
    // Hiker walks backward (left)
    var hikerX = 140 - (p * 100);
    hiker.setAttribute('transform', 'translate(' + hikerX + ',155)');
    // All cloud / callouts off
    sprayCloud.setAttribute('opacity', '0');
    sprayCloud.classList.remove('spraying');
    callout1.setAttribute('opacity', '0');
    callout2.setAttribute('opacity', '0');
    callout3.setAttribute('opacity', '0');
    sprayCan.setAttribute('opacity', '0');
    // Arms relaxed
    armR.setAttribute('x2', '30');
    armR.setAttribute('y2', '55');
    armL.setAttribute('x2', '-6');
    armL.setAttribute('y2', '55');
  }

  sprayAnimState.rafId = requestAnimationFrame(animLoop);
}

function resetAnimElements() {
  var hiker = document.getElementById('anim-hiker');
  var bear = document.getElementById('anim-bear');
  var sprayCloud = document.getElementById('anim-spray-cloud');
  var hikerAlert = document.getElementById('hiker-alert');
  var sprayCan = document.getElementById('hiker-spray-can');
  var armL = document.getElementById('hiker-arm-l');
  var armR = document.getElementById('hiker-arm-r');
  var callout1 = document.getElementById('callout-1');
  var callout2 = document.getElementById('callout-2');
  var callout3 = document.getElementById('callout-3');

  if (hiker) hiker.setAttribute('transform', 'translate(140,155)');
  if (bear) bear.setAttribute('transform', 'translate(750,170)');
  if (sprayCloud) {
    sprayCloud.setAttribute('opacity', '0');
    sprayCloud.classList.remove('spraying');
    sprayCloud.removeAttribute('transform');
  }
  if (hikerAlert) {
    hikerAlert.setAttribute('opacity', '0');
    hikerAlert.classList.remove('show');
  }
  if (sprayCan) sprayCan.setAttribute('opacity', '0');
  if (armL) { armL.setAttribute('x2', '-6'); armL.setAttribute('y2', '55'); }
  if (armR) { armR.setAttribute('x2', '30'); armR.setAttribute('y2', '55'); }
  if (callout1) callout1.setAttribute('opacity', '0');
  if (callout2) callout2.setAttribute('opacity', '0');
  if (callout3) callout3.setAttribute('opacity', '0');
}
